import { GoogleGenAI } from "@google/genai";
import { TOOLS } from '../constants';

const getSystemInstruction = () => {
  const toolContext = TOOLS.map(t => 
    `- ${t.name} (${t.category}): ${t.description}`
  ).join('\n');

  return `You are the AI Concierge for "Northbrand Collective", the personal portfolio and digital hub of a photographer and developer based in Abilene, TX.

  The creator (brondolfr.lo) has a background in photography (check @brondolfr.lo on IG), development (GitHub/Vercel projects), military/VA advocacy, and community involvement (Wylie High School).

  Here is the current collection of projects and focus areas:
  ${toolContext}

  Your tone should be:
  - Sophisticated but grounded.
  - Enthusiastic about photography and technical clarity.
  - Respectful and knowledgeable about military service and local Abilene life.

  When users ask about projects, refer to the Vercel and GitHub links. If they ask about style, mention the moody, minimal photography.
  Keep answers concise (under 3 sentences) to fit the chat UI.`;
};

export const sendMessageToGemini = async (history: {role: string, text: string}[], newMessage: string): Promise<string> => {
  try {
    let apiKey: string | undefined;

    try {
      apiKey = process.env.API_KEY;
    } catch (e) {
      console.warn("Accessing process.env failed");
    }

    if (!apiKey) {
      return "I'm sorry, I cannot connect to the server right now. (Missing API Key)";
    }

    const ai = new GoogleGenAI({ apiKey });

    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: getSystemInstruction(),
      }
    });

    const result = await chat.sendMessage({ message: newMessage });
    return result.text;

  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I apologize, but I seem to be having trouble reaching our archives at the moment.";
  }
};

