import React, { useState, useMemo } from 'react';
import { TOOLS } from '../constants';
import { Tool } from '../types';
import ProductCard from './ProductCard';

const categories = ['All', 'Photography', 'Development', 'Military/VA', 'Community', 'Retirement'];

interface ProductGridProps {
  onToolClick: (tool: Tool) => void;
}

const ProductGrid: React.FC<ProductGridProps> = ({ onToolClick }) => {
  const [activeCategory, setActiveCategory] = useState('All');

  const filteredTools = useMemo(() => {
    if (activeCategory === 'All') return TOOLS;
    return TOOLS.filter(t => t.category === activeCategory);
  }, [activeCategory]);

  return (
    <section id="tools" className="py-32 px-6 md:px-12 bg-[#F5F2EB]">
      <div className="max-w-[1800px] mx-auto">

        {/* Header Area */}
        <div className="flex flex-col items-center text-center mb-24 space-y-8">
          <h2 className="text-4xl md:text-6xl font-serif text-[#2C2A26]">The Collection</h2>

          {/* Minimal Filter */}
          <div className="flex flex-wrap justify-center gap-8 pt-4 border-t border-[#D6D1C7]/50 w-full max-w-3xl">
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`text-sm uppercase tracking-widest pb-1 border-b transition-all duration-300 ${
                  activeCategory === cat 
                    ? 'border-[#2C2A26] text-[#2C2A26]' 
                    : 'border-transparent text-[#A8A29E] hover:text-[#2C2A26]'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        {/* Large Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-x-8 gap-y-20">
          {filteredTools.map(tool => (
            <ProductCard key={tool.id} tool={tool} onClick={onToolClick} />
          ))}
        </div>
      </div>
    </section>
  );
};

export default ProductGrid;

