import ProductCard from './ProductCard';

const categories = ['All', 'Photography', 'Development', 'Military/VA', 'Community', 'Retirement'];

interface ProductGridProps {
  onToolClick: (tool: Tool) => void;
  isDarkMode: boolean;
}

const ProductGrid: React.FC<ProductGridProps> = ({ onToolClick, isDarkMode }) => {
  const [activeCategory, setActiveCategory] = useState('All');

  const filteredTools = useMemo(() => {
    if (activeCategory === 'All') return TOOLS;
    return TOOLS.filter(t => t.category === activeCategory);
  }, [activeCategory]);

  const textColor = isDarkMode ? 'text-[#F5F2EB]' : 'text-[#2C2A26]';
  const borderColor = isDarkMode ? 'border-[#3D3B36]' : 'border-[#D6D1C7]';

  return (
    <section id="tools" className={`py-32 px-6 md:px-12 transition-colors duration-500 ${isDarkMode ? 'bg-[#1A1917]' : 'bg-[#F5F2EB]'}`}>
      <div className="max-w-[1800px] mx-auto">

        {/* Header Area */}
        <div className="flex flex-col items-center text-center mb-24 space-y-8">
          <h2 className={`text-4xl md:text-6xl font-serif ${textColor}`}>The Collection</h2>

          {/* Minimal Filter */}
          <div className={`flex flex-wrap justify-center gap-8 pt-4 border-t ${borderColor}/50 w-full max-w-3xl`}>
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`text-sm uppercase tracking-widest pb-1 border-b transition-all duration-300 ${
                  activeCategory === cat 
                    ? `border-${isDarkMode ? '[#F5F2EB]' : '[#2C2A26]'} ${textColor}` 
                    : `border-transparent text-[#A8A29E] hover:${textColor}`
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        {/* Large Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-x-8 gap-y-20">
