import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import ProductGrid from './components/ProductGrid';
import About from './components/About';
import Journal from './components/Journal';
import Footer from './components/Footer';
import ProductDetail from './components/ProductDetail';
import JournalDetail from './components/JournalDetail';
import { ViewState } from './types';

function App() {
  const [view, setView] = useState<ViewState>({ type: 'home' });
  const [isDarkMode, setIsDarkMode] = useState(false);

  // Toggle theme
  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  // Handle navigation
  const handleNavClick = (e: React.MouseEvent<HTMLAnchorElement>, targetId: string) => {
    e.preventDefault();

    if (view.type !== 'home') {
      setView({ type: 'home' });
      setTimeout(() => scrollToSection(targetId), 0);
    } else {
      scrollToSection(targetId);
    }
  };

  const scrollToSection = (targetId: string) => {
    if (!targetId) {
        window.scrollTo({ top: 0, behavior: 'smooth' });
        return;
    }

    const element = document.getElementById(targetId);
    if (element) {
      const headerOffset = 85;
      const elementPosition = element.getBoundingClientRect().top;
      const offsetPosition = elementPosition + window.scrollY - headerOffset;

      window.scrollTo({
        top: offsetPosition,
        behavior: "smooth"
      });

      try {
        window.history.pushState(null, '', `#${targetId}`);
      } catch (err) {}
    }
  };

  const themeClasses = isDarkMode 
    ? 'bg-[#1A1917] text-[#F5F2EB] selection:bg-[#3D3B36] selection:text-[#F5F2EB]' 
    : 'bg-[#F5F2EB] text-[#2C2A26] selection:bg-[#D6D1C7] selection:text-[#2C2A26]';

  return (
    <div className={`min-h-screen font-sans transition-colors duration-500 ${themeClasses}`}>
      <Navbar 
        onNavClick={handleNavClick} 
        isDarkMode={isDarkMode}
        onToggleTheme={toggleTheme}
      />

      <main>
        {view.type === 'home' && (
          <>
            <Hero />
            <div className={isDarkMode ? 'bg-[#1A1917]' : 'bg-[#F5F2EB]'}>
              <ProductGrid 
                isDarkMode={isDarkMode}
                onToolClick={(t) => {
                  window.scrollTo({ top: 0, behavior: 'smooth' });
                  setView({ type: 'tool', tool: t });
                }} 
              />
              <About isDarkMode={isDarkMode} />
              <Journal 
                isDarkMode={isDarkMode}
                onArticleClick={(a) => {
                  window.scrollTo({ top: 0, behavior: 'smooth' });
                  setView({ type: 'journal', article: a });
                }} 
              />
            </div>
          </>
        )}

        {view.type === 'tool' && (
          <ProductDetail 
            tool={view.tool} 
            isDarkMode={isDarkMode}
            onBack={() => {
              setView({ type: 'home' });
              setTimeout(() => scrollToSection('tools'), 50);
            }}
          />
        )}

        {view.type === 'journal' && (
          <JournalDetail 
            article={view.article} 
            isDarkMode={isDarkMode}
            onBack={() => setView({ type: 'home' })}
          />
        )}
      </main>

      <Footer onLinkClick={handleNavClick} isDarkMode={isDarkMode} />
    </div>
  );
}

export default App;

